import{_ as p,c as l}from"./app.f21a7cce.js";const i={},s=l('<h1 id="_28-\u8BB2-\u5E26\u4F60\u4E00\u8D77\u89E3\u8BFB\u4E0D\u540C\u89C6\u89D2\u7684\u8F6F\u4EF6\u6027\u80FD\u4E0E\u6027\u80FD\u6307\u6807" tabindex="-1"><a class="header-anchor" href="#_28-\u8BB2-\u5E26\u4F60\u4E00\u8D77\u89E3\u8BFB\u4E0D\u540C\u89C6\u89D2\u7684\u8F6F\u4EF6\u6027\u80FD\u4E0E\u6027\u80FD\u6307\u6807" aria-hidden="true">#</a> 28 \u8BB2\uFF1A\u5E26\u4F60\u4E00\u8D77\u89E3\u8BFB\u4E0D\u540C\u89C6\u89D2\u7684\u8F6F\u4EF6\u6027\u80FD\u4E0E\u6027\u80FD\u6307\u6807</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u5E26\u4F60\u4E00\u8D77\u89E3\u8BFB\u4E0D\u540C\u89C6\u89D2\u7684\u8F6F\u4EF6\u6027\u80FD\u4E0E\u6027\u80FD\u6307\u6807\u3002</p><p>\u6211\u7528\u4E09\u7BC7\u6587\u7AE0\u7684\u7BC7\u5E45\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u4EE3\u7801\u7EA7\u6D4B\u8BD5\u7684\u4E00\u4E9B\u57FA\u672C\u6982\u5FF5\u548C\u6D4B\u8BD5\u65B9\u6CD5\uFF0C\u5E0C\u671B\u53EF\u4EE5\u5E2E\u52A9\u4F60\u89E3\u51B3\u5728\u5B9E\u9645\u5DE5\u4F5C\u4E2D\u9047\u5230\u7684\u95EE\u9898\uFF0C\u5982\u679C\u4F60\u611F\u89C9\u8FD8\u6709\u4E00\u4E9B\u95EE\u9898\u6CA1\u6709\u89E3\u51B3\u7684\u8BDD\uFF0C\u6B22\u8FCE\u4F60\u7ED9\u6211\u7559\u8A00\uFF0C\u6211\u4EEC\u4E00\u8D77\u53BB\u8BA8\u8BBA\u3001\u89E3\u51B3\u3002</p><p>\u4ECE\u4ECA\u5929\u5F00\u59CB\uFF0C\u6211\u5C06\u548C\u4F60\u5206\u4EAB\u4E00\u4E2A\u65B0\u7684\u6D4B\u8BD5\u4E3B\u9898\uFF1A\u6027\u80FD\u6D4B\u8BD5\u3002\u8FD9\u4E2A\u7CFB\u5217\uFF0C\u6211\u51C6\u5907\u4E86\u4E03\u4E2A\u4E3B\u9898\uFF0C\u8981\u548C\u4F60\u8BE6\u7EC6\u804A\u804A\u8F6F\u4EF6\u6027\u80FD\u6D4B\u8BD5\u76F8\u5173\u7684\u77E5\u8BC6\u70B9\u3002</p><p>\u56E0\u4E3A\u6027\u80FD\u6D4B\u8BD5\u7684\u4E13\u4E1A\u6027\u5F88\u5F3A\uFF0C\u6240\u4EE5\u6211\u4F1A\u4EE5\u4ECE 0 \u5230 1 \u7684\u5165\u95E8\u8005\u89C6\u89D2\uFF0C\u7CFB\u7EDF\u6027\u5730\u9610\u8FF0\u6027\u80FD\u6D4B\u8BD5\u7684\u65B9\u6CD5\u4EE5\u53CA\u5E94\u7528\u9886\u57DF\uFF0C\u7528\u5B9E\u4F8B\u53BB\u8BE0\u91CA\u5404\u79CD\u6027\u80FD\u6307\u6807\uFF1B\u6211\u8FD8\u4F1A\u5206\u4EAB\u4E00\u4E9B\u524D\u7AEF\u548C\u540E\u7AEF\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u57FA\u672C\u539F\u7406\uFF0C\u5E76\u57FA\u4E8E LoadRunner \u53BB\u5206\u6790\u4E00\u4E9B\u5927\u578B\u4F01\u4E1A\u6027\u80FD\u6D4B\u8BD5\u7684\u89C4\u5212\u3001\u8BBE\u8BA1\u3001\u5B9E\u73B0\u7684\u5177\u4F53\u5B9E\u4F8B\uFF1B\u6211\u8FD8\u4F1A\u548C\u4F60\u5206\u4EAB\u4E00\u4E9B\u8DE8\u56FD\u8F6F\u4EF6\u516C\u53F8\u6027\u80FD\u6D4B\u8BD5\u5353\u8D8A\u4E2D\u5FC3\u7684\u5B9E\u9645\u6848\u4F8B\u3002</p><p>\u5E0C\u671B\u8FD9\u4E2A\u7CFB\u5217\u7684\u5185\u5BB9\uFF0C\u53EF\u4EE5\u5B8C\u5584\u4F60\u7684\u6027\u80FD\u6D4B\u8BD5\u77E5\u8BC6\u4F53\u7CFB\uFF0C\u771F\u771F\u6B63\u6B63\u5730\u5E2E\u4F60\u89E3\u51B3\u5B9E\u9645\u9879\u76EE\u4E2D\u9047\u5230\u7684\u95EE\u9898\u3002</p><p>\u90A3\u4E48\uFF0C\u4F5C\u4E3A\u6027\u80FD\u6D4B\u8BD5\u7CFB\u5217\u7684\u7B2C\u4E00\u6B21\u5206\u4EAB\uFF0C\u6211\u4F1A\u7AD9\u5728\u5168\u5C40\u7684\u89C6\u89D2\uFF0C\u5E2E\u4F60\u68B3\u7406\u8F6F\u4EF6\u6027\u80FD\u3001\u8F6F\u4EF6\u6027\u80FD\u6D4B\u8BD5\u76F8\u5173\u7684\u77E5\u8BC6\u70B9\uFF0C\u8BA9\u4F60\u5BF9\u90A3\u4E9B\u4F60\u6216\u8BB8\u5DF2\u7ECF\u8033\u719F\u80FD\u8BE6\u7684\u6027\u80FD\u6307\u6807\u6709\u4E00\u4E2A\u66F4\u6E05\u6670\u7684\u7406\u89E3\uFF0C\u4E3A\u4F60\u5B8C\u6210\u540E\u7EED\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u4F5C\u6253\u597D\u57FA\u7840\u3002</p><p>\u5982\u679C\u4F60\u5BF9\u8F6F\u4EF6\u6027\u80FD\u7684\u7406\u89E3\u8FD8\u505C\u7559\u5728\u54CD\u5E94\u65F6\u95F4\u7684\u5FEB\u6162\u4E0A\uFF0C\u90A3\u4E48\u8D76\u7D27\u548C\u6211\u4E00\u8D77\u5F00\u59CB\u4ECA\u5929\u7684\u5185\u5BB9\u5427\u3002</p><p><strong>\u5728\u5F00\u59CB\u4E0B\u9762\u7684\u5185\u5BB9\u524D\uFF0C\u8BF7\u4F60\u5148\u601D\u8003\u4E00\u4E2A\u95EE\u9898\uFF1A\u5F53\u6211\u4EEC\u8C08\u53CA\u8F6F\u4EF6\u6027\u80FD\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u5230\u5E95\u8C08\u7684\u662F\u4EC0\u4E48\uFF1F</strong></p><p>\u76EE\u524D\uFF0C\u5BF9\u8F6F\u4EF6\u6027\u80FD\u6700\u666E\u904D\u7684\u7406\u89E3\u5C31\u662F\u8F6F\u4EF6\u5904\u7406\u7684\u53CA\u65F6\u6027\u3002\u4F46\u5176\u5B9E\uFF0C\u4ECE\u4E0D\u540C\u7684\u7CFB\u7EDF\u7C7B\u578B\uFF0C\u4EE5\u53CA\u4E0D\u540C\u7684\u89C6\u89D2\u53BB\u8BA8\u8BBA\u8F6F\u4EF6\u6027\u80FD\uFF0C\u90FD\u4F1A\u6709\u6240\u533A\u522B\u3002</p><p>\u5BF9\u4E8E\u4E0D\u540C\u7C7B\u578B\u7684\u7CFB\u7EDF\uFF0C\u8F6F\u4EF6\u6027\u80FD\u7684\u5173\u6CE8\u70B9\u5404\u4E0D\u76F8\u540C\uFF0C\u6BD4\u5982\uFF1A</p><p>Web \u7C7B\u5E94\u7528\u548C\u624B\u673A\u7AEF\u5E94\u7528\uFF0C\u4E00\u822C\u4EE5\u7EC8\u7AEF\u7528\u6237\u611F\u53D7\u5230\u7684\u7AEF\u5230\u7AEF\u7684\u54CD\u5E94\u65F6\u95F4\u6765\u63CF\u8FF0\u7CFB\u7EDF\u7684\u6027\u80FD\uFF1B \u975E\u4EA4\u4E92\u5F0F\u7684\u5E94\u7528\uFF0C\u6BD4\u5982\u5178\u578B\u7684\u7535\u4FE1\u548C\u94F6\u884C\u540E\u53F0\u5904\u7406\u7CFB\u7EDF\uFF0C\u54CD\u5E94\u65F6\u95F4\u5173\u6CE8\u66F4\u591A\u7684\u662F\u4E8B\u4EF6\u5904\u7406\u7684\u901F\u5EA6\uFF0C\u4EE5\u53CA\u5355\u4F4D\u65F6\u95F4\u7684\u4E8B\u4EF6\u541E\u5410\u91CF\u3002 \u8FD9\u5F88\u5BB9\u6613\u7406\u89E3\u3002\u540C\u6837\u5730\uFF0C\u5BF9\u540C\u4E00\u4E2A\u7CFB\u7EDF\u6765\u8BF4\uFF0C\u4E0D\u540C\u7684\u5BF9\u8C61\u7FA4\u4F53\u5BF9\u8F6F\u4EF6\u6027\u80FD\u7684\u5173\u6CE8\u70B9\u548C\u671F\u671B\u4E5F\u4E0D\u5B8C\u5168\u76F8\u540C\uFF0C\u751A\u81F3\u5F88\u591A\u65F6\u5019\u662F\u5BF9\u7ACB\u7684\u3002\u8FD9\u91CC\uFF0C\u4E0D\u540C\u7684\u5BF9\u8C61\u7FA4\u4F53\u53EF\u4EE5\u5206\u4E3A\u56DB\u5927\u7C7B\uFF1A\u7EC8\u7AEF\u7528\u6237\u3001\u7CFB\u7EDF\u8FD0\u7EF4\u4EBA\u5458\u3001\u8F6F\u4EF6\u8BBE\u8BA1\u5F00\u53D1\u4EBA\u5458\u548C\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u3002</p><p><img src="https://static001.geekbang.org/resource/image/73/2d/73607121b26944c77f657e62a8894e2d.png" alt="\u8861\u91CF\u8F6F\u4EF6\u6027\u80FD\u7684\u56DB\u4E2A\u7EF4\u5EA6"></p><p>\u7EC8\u7AEF\u7528\u6237\u662F\u8F6F\u4EF6\u7CFB\u7EDF\u7684\u6700\u7EC8\u4F7F\u7528\u8005\uFF0C\u4ED6\u4EEC\u5BF9\u8F6F\u4EF6\u6027\u80FD\u7684\u53CD\u9988\u76F4\u63A5\u51B3\u5B9A\u4E86\u8FD9\u4E2A\u7CFB\u7EDF\u7684\u5E94\u7528\u524D\u666F\uFF1B\u800C\uFF0C\u8F6F\u4EF6\u5F00\u53D1\u4EBA\u5458\u3001\u8FD0\u7EF4\u4EBA\u5458\u3001\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\uFF0C\u5BF9\u6027\u80FD\u6D4B\u8BD5\u7684\u5173\u6CE8\u70B9\u5219\u76F4\u63A5\u51B3\u5B9A\u4E86\u4E00\u4E2A\u7CFB\u7EDF\u4EA4\u4ED8\u5230\u7528\u6237\u624B\u4E2D\u7684\u6027\u80FD\u3002</p><p>\u53EA\u6709\u5168\u9762\u4E86\u89E3\u5404\u7C7B\u7FA4\u4F53\u5BF9\u8F6F\u4EF6\u7CFB\u7EDF\u7684\u4E0D\u540C\u9700\u6C42\uFF0C\u624D\u80FD\u4FDD\u8BC1\u8FD9\u4E2A\u7CFB\u7EDF\u5177\u6709\u771F\u6B63\u9AD8\u53EF\u9760\u7684\u6027\u80FD\u3002\u6240\u4EE5\uFF0C\u63A5\u4E0B\u6765\u6211\u4F1A\u4ECE\u8FD9\u56DB\u7C7B\u4EBA\u7684\u89C6\u89D2\u548C\u7EF4\u5EA6\u53BB\u5206\u4EAB\u8F6F\u4EF6\u6027\u80FD\u5230\u5E95\u6307\u7684\u662F\u4EC0\u4E48\u3002</p><p><strong>\u7EC8\u7AEF\u7528\u6237\u773C\u4E2D\u7684\u8F6F\u4EF6\u6027\u80FD</strong></p><p>\u4ECE\u7EC8\u7AEF\u7528\u6237\uFF08\u4E5F\u5C31\u662F\u8F6F\u4EF6\u7CFB\u7EDF\u4F7F\u7528\u8005\uFF09\u7684\u7EF4\u5EA6\u6765\u8BB2\uFF0C\u8F6F\u4EF6\u6027\u80FD\u8868\u73B0\u4E3A\u7528\u6237\u8FDB\u884C\u4E1A\u52A1\u64CD\u4F5C\u65F6\u7684\u4E3B\u89C2\u54CD\u5E94\u65F6\u95F4\u3002\u5177\u4F53\u6765\u8BB2\u5C31\u662F\uFF0C\u4ECE\u7528\u6237\u5728\u754C\u9762\u4E0A\u5B8C\u6210\u4E00\u4E2A\u64CD\u4F5C\u5F00\u59CB\uFF0C\u5230\u7CFB\u7EDF\u628A\u672C\u6B21\u64CD\u4F5C\u7684\u7ED3\u679C\u4EE5\u7528\u6237\u80FD\u5BDF\u89C9\u7684\u65B9\u5F0F\u5C55\u73B0\u51FA\u6765\u7684\u5168\u90E8\u65F6\u95F4\u3002\u5BF9\u7EC8\u7AEF\u7528\u6237\u6765\u8BF4\uFF0C\u8FD9\u4E2A\u65F6\u95F4\u8D8A\u77ED\u4F53\u9A8C\u8D8A\u597D\u3002</p><p>\u8FD9\u4E2A\u54CD\u5E94\u65F6\u95F4\u662F\u7EC8\u7AEF\u7528\u6237\u5BF9\u7CFB\u7EDF\u6027\u80FD\u7684\u6700\u76F4\u89C2\u5370\u8C61\uFF0C\u5305\u62EC\u4E86\u7CFB\u7EDF\u54CD\u5E94\u65F6\u95F4\u548C\u524D\u7AEF\u5C55\u73B0\u65F6\u95F4\u3002</p><p>\u7CFB\u7EDF\u54CD\u5E94\u65F6\u95F4\uFF0C\u53CD\u5E94\u7684\u662F\u7CFB\u7EDF\u80FD\u529B\uFF0C\u53C8\u53EF\u4EE5\u8FDB\u4E00\u6B65\u7EC6\u5206\u4E3A\u5E94\u7528\u7CFB\u7EDF\u5904\u7406\u65F6\u95F4\u3001\u6570\u636E\u5E93\u5904\u7406\u65F6\u95F4\u548C\u7F51\u7EDC\u4F20\u8F93\u65F6\u95F4\u7B49\uFF1B \u524D\u7AEF\u5C55\u73B0\u65F6\u95F4\uFF0C\u53D6\u51B3\u4E8E\u7528\u6237\u7AEF\u7684\u5904\u7406\u80FD\u529B\u3002 \u4ECE\u8FD9\u4E2A\u89D2\u5EA6\u6765\u770B\uFF0C\u4F60\u5C31\u53EF\u4EE5\u975E\u5E38\u5BB9\u6613\u7406\u89E3\u6027\u80FD\u6D4B\u8BD5\u4E3A\u4EC0\u4E48\u4F1A\u5206\u4E3A\u540E\u7AEF\uFF08\u670D\u52A1\u5668\u7AEF\uFF09\u7684\u6027\u80FD\u6D4B\u8BD5\u548C\u524D\u7AEF\uFF08\u901A\u5E38\u662F\u6D4F\u89C8\u5668\u7AEF\uFF09\u7684\u6027\u80FD\u6D4B\u8BD5\u4E86\u3002</p><p><strong>\u7CFB\u7EDF\u8FD0\u7EF4\u4EBA\u5458\u773C\u4E2D\u7684\u8F6F\u4EF6\u6027\u80FD</strong></p><p>\u4ECE\u8F6F\u4EF6\u7CFB\u7EDF\u8FD0\u7EF4\uFF08\u4E5F\u5C31\u662F\u7CFB\u7EDF\u8FD0\u7EF4\u4EBA\u5458\uFF09\u7684\u89D2\u5EA6\uFF0C\u8F6F\u4EF6\u6027\u80FD\u9664\u4E86\u5305\u62EC\u5355\u4E2A\u7528\u6237\u7684\u54CD\u5E94\u65F6\u95F4\u5916\uFF0C\u66F4\u8981\u5173\u6CE8\u5927\u91CF\u7528\u6237\u5E76\u53D1\u8BBF\u95EE\u65F6\u7684\u8D1F\u8F7D\uFF0C\u4EE5\u53CA\u53EF\u80FD\u7684\u66F4\u5927\u8D1F\u8F7D\u60C5\u51B5\u4E0B\u7684\u7CFB\u7EDF\u5065\u5EB7\u72B6\u6001\u3001\u5E76\u53D1\u5904\u7406\u80FD\u529B\u3001\u5F53\u524D\u90E8\u7F72\u7684\u7CFB\u7EDF\u5BB9\u91CF\u3001\u53EF\u80FD\u7684\u7CFB\u7EDF\u74F6\u9888\u3001\u7CFB\u7EDF\u914D\u7F6E\u5C42\u9762\u7684\u8C03\u4F18\u3001\u6570\u636E\u5E93\u7684\u8C03\u4F18\uFF0C\u4EE5\u53CA\u957F\u65F6\u95F4\u8FD0\u884C\u7A33\u5B9A\u6027\u548C\u53EF\u6269\u5C55\u6027\u3002</p><p>\u5927\u591A\u6570\u60C5\u51B5\u4E0B\uFF0C\u7CFB\u7EDF\u8FD0\u7EF4\u4EBA\u5458\u548C\u7EC8\u7AEF\u7528\u6237\u662F\u7AD9\u5728\u540C\u4E00\u6761\u6218\u7EBF\u4E0A\u7684\uFF0C\u5E0C\u671B\u7CFB\u7EDF\u7684\u54CD\u5E94\u901F\u5EA6\u5C3D\u53EF\u80FD\u5730\u5FEB\u3002\u4F46\uFF0C\u67D0\u4E9B\u60C5\u51B5\u4E0B\u4ED6\u4EEC\u7684\u610F\u89C1\u662F\u5BF9\u7ACB\u7684\uFF0C\u6700\u5E38\u89C1\u7684\u60C5\u51B5\u5C31\u662F\uFF0C\u7CFB\u7EDF\u8FD0\u7EF4\u4EBA\u5458\u5FC5\u987B\u5728\u6700\u5927\u5E76\u53D1\u7528\u6237\u6570\u548C\u7CFB\u7EDF\u54CD\u5E94\u65F6\u95F4\u4E4B\u95F4\u8FDB\u884C\u6743\u8861\u53D6\u820D\u3002\u6BD4\u5982\uFF0C\u5F53\u6709\u4E24\u5957\u7CFB\u7EDF\u914D\u7F6E\u65B9\u6848\u53EF\u4EE5\u63D0\u4F9B\u4EE5\u4E0B\u7CFB\u7EDF\u80FD\u529B\u7684\u65F6\uFF1A</p><p>\u914D\u7F6E\u65B9\u6848 A \u53EF\u4EE5\u63D0\u4F9B 100 \u4E07\u5E76\u53D1\u8BBF\u95EE\u7528\u6237\u7684\u80FD\u529B\uFF0C\u6B64\u65F6\u7528\u6237\u7684\u767B\u5F55\u54CD\u5E94\u65F6\u95F4\u662F 3 \u79D2\uFF1B \u914D\u7F6E\u65B9\u6848 B \u53EF\u4EE5\u63D0\u4F9B 500 \u4E07\u5E76\u53D1\u8BBF\u95EE\u7528\u6237\u7684\u80FD\u529B\uFF0C\u6B64\u65F6\u7528\u6237\u7684\u767B\u5F55\u54CD\u5E94\u65F6\u95F4\u662F 8 \u79D2\u3002 \u8FD9\u65F6\uFF0C\u4ECE\u5168\u5C40\u5229\u76CA\u6700\u5927\u5316\u89D2\u5EA6\u6765\u770B\uFF0C\u7CFB\u7EDF\u5177\u6709\u66F4\u5927\u5E76\u53D1\u7528\u6237\u627F\u8F7D\u80FD\u529B\u7684\u4EF7\u503C\u4F1A\u66F4\u5927\uFF0C\u6240\u4EE5\u8FD0\u7EF4\u4EBA\u5458\u4E00\u822C\u90FD\u4F1A\u9009\u62E9\u65B9\u6848 B\u3002</p><p><strong>\u76EE\u524D\uFF0C\u6709\u4E9B\u7CFB\u7EDF\u4E3A\u4E86\u80FD\u591F\u627F\u8F7D\u66F4\u591A\u7684\u5E76\u53D1\u7528\u6237\uFF0C\u5F80\u5F80\u4F1A\u727A\u7272\u7B49\u5F85\u65F6\u95F4\u800C\u5F15\u5165\u9884\u671F\u7684\u7B49\u5F85\u673A\u5236</strong>\u3002\u6BD4\u5982\uFF0C\u706B\u8F66\u7968\u8D2D\u7968\u7F51\u7AD9\uFF0C\u5C31\u5728\u5904\u7406\u6781\u5927\u5E76\u53D1\u7528\u6237\u65F6\u91C7\u7528\u4E86\u6392\u961F\u673A\u5236\uFF0C\u4EE5\u5C3D\u53EF\u80FD\u63D0\u9AD8\u7CFB\u7EDF\u5BB9\u91CF\uFF0C\u4F46\u5374\u589E\u52A0\u4E86\u7528\u6237\u5B9E\u9645\u611F\u53D7\u5230\u7684\u54CD\u5E94\u65F6\u95F4\u3002</p><p><strong>\u8F6F\u4EF6\u8BBE\u8BA1\u5F00\u53D1\u4EBA\u5458\u773C\u4E2D\u7684\u8F6F\u4EF6\u6027\u80FD</strong></p><p>\u4ECE\u8F6F\u4EF6\u7CFB\u7EDF\u5F00\u53D1\uFF08\u4E5F\u5C31\u662F\u8F6F\u4EF6\u8BBE\u8BA1\u5F00\u53D1\u4EBA\u5458\uFF09\u7684\u89D2\u5EA6\u6765\u8BB2\uFF0C\u8F6F\u4EF6\u6027\u80FD\u5173\u6CE8\u7684\u662F\u6027\u80FD\u76F8\u5173\u7684\u8BBE\u8BA1\u548C\u5B9E\u73B0\u7EC6\u8282\uFF0C\u8FD9\u51E0\u4E4E\u6DB5\u76D6\u4E86\u8F6F\u4EF6\u8BBE\u8BA1\u548C\u5F00\u53D1\u7684\u5168\u8FC7\u7A0B\u3002</p><p>\u5728\u5927\u578B\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\u4E2D\uFF0C\u8F6F\u4EF6\u6027\u80FD\u7EDD\u4E0D\u4EC5\u4EC5\u662F\u6027\u80FD\u6D4B\u8BD5\u9636\u6BB5\u8981\u8003\u8651\u7684\u95EE\u9898\uFF0C\u800C\u662F\u6574\u4E2A\u8F6F\u4EF6\u7814\u53D1\u751F\u547D\u5468\u671F\u90FD\u8981\u8003\u8651\u7684\u5185\u5BB9\uFF0C\u6211\u4EEC\u5F80\u5F80\u628A\u56F4\u7ED5\u6027\u80FD\u76F8\u5173\u7684\u6D3B\u52A8\u79F0\u4E3A\u201C\u6027\u80FD\u5DE5\u7A0B\u201D\uFF08Performance Engineering\uFF09\u3002\u6211\u66FE\u5728\u60E0\u666E\u8F6F\u4EF6\u7814\u53D1\u4E2D\u5FC3\u7684\u6027\u80FD\u6D4B\u8BD5\u5353\u8D8A\u4E2D\u5FC3\u8D1F\u8D23\u8FD9\u65B9\u9762\u7684\u6280\u672F\u5DE5\u4F5C\uFF0C\u6240\u4EE5\u611F\u53D7\u9887\u6DF1\u3002</p><p>\u5728\u8F6F\u4EF6\u8BBE\u8BA1\u5F00\u53D1\u4EBA\u5458\u773C\u4E2D\uFF0C\u8F6F\u4EF6\u6027\u80FD\u901A\u5E38\u4F1A\u5305\u542B\u7B97\u6CD5\u8BBE\u8BA1\u3001\u67B6\u6784\u8BBE\u8BA1\u3001\u6027\u80FD\u6700\u4F73\u5B9E\u8DF5\u3001\u6570\u636E\u5E93\u76F8\u5173\u3001\u8F6F\u4EF6\u6027\u80FD\u7684\u53EF\u6D4B\u8BD5\u6027\u8FD9\u4E94\u5927\u65B9\u9762\u3002\u5176\u4E2D\uFF0C\u6BCF\u4E2A\u65B9\u9762\u5173\u6CE8\u7684\u70B9\uFF0C\u4E5F\u5305\u62EC\u5F88\u591A\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u7B97\u6CD5\u8BBE\u8BA1\u5305\u542B\u7684\u70B9\uFF1A</strong></p><ul><li>\u6838\u5FC3\u7B97\u6CD5\u7684\u8BBE\u8BA1\u4E0E\u5B9E\u73B0\u662F\u5426\u9AD8\u6548\uFF1B</li><li>\u5FC5\u8981\u65F6\uFF0C\u8BBE\u8BA1\u4E0A\u662F\u5426\u91C7\u7528 buffer \u673A\u5236\u4EE5\u63D0\u9AD8\u6027\u80FD\uFF0C\u964D\u4F4E I/O\uFF1B</li><li>\u662F\u5426\u5B58\u5728\u6F5C\u5728\u7684\u5185\u5B58\u6CC4\u9732\uFF1B</li><li>\u662F\u5426\u5B58\u5728\u5E76\u53D1\u73AF\u5883\u4E0B\u7684\u7EBF\u7A0B\u5B89\u5168\u95EE\u9898\uFF1B</li><li>\u662F\u5426\u5B58\u5728\u4E0D\u5408\u7406\u7684\u7EBF\u7A0B\u540C\u6B65\u65B9\u5F0F\uFF1B</li><li>\u662F\u5426\u5B58\u5728\u4E0D\u5408\u7406\u7684\u8D44\u6E90\u7ADE\u4E89\u3002</li></ul><p><strong>\u7B2C\u4E8C\uFF0C\u67B6\u6784\u8BBE\u8BA1\u5305\u542B\u7684\u5185\u5BB9\uFF1A</strong></p><ul><li>\u7AD9\u5728\u6574\u4F53\u7CFB\u7EDF\u7684\u89D2\u5EA6\uFF0C\u662F\u5426\u53EF\u4EE5\u65B9\u4FBF\u5730\u8FDB\u884C\u7CFB\u7EDF\u5BB9\u91CF\u548C\u6027\u80FD\u6269\u5C55\uFF1B</li><li>\u5E94\u7528\u96C6\u7FA4\u7684\u53EF\u6269\u5C55\u6027\u662F\u5426\u7ECF\u8FC7\u6D4B\u8BD5\u548C\u9A8C\u8BC1\uFF1B</li><li>\u7F13\u5B58\u96C6\u7FA4\u7684\u53EF\u6269\u5C55\u6027\u662F\u5426\u7ECF\u8FC7\u6D4B\u8BD5\u548C\u9A8C\u8BC1\uFF1B</li><li>\u6570\u636E\u5E93\u7684\u53EF\u6269\u5C55\u6027\u662F\u5426\u7ECF\u8FC7\u6D4B\u8BD5\u548C\u9A8C\u8BC1\u3002</li></ul><p><strong>\u7B2C\u4E09\uFF0C\u6027\u80FD\u6700\u4F73\u5B9E\u8DF5\u5305\u542B\u7684\u70B9\uFF1A</strong></p><ul><li>\u4EE3\u7801\u5B9E\u73B0\u662F\u5426\u9075\u5B88\u5F00\u53D1\u8BED\u8A00\u7684\u6027\u80FD\u6700\u4F73\u5B9E\u8DF5\uFF1B</li><li>\u5173\u952E\u4EE3\u7801\u662F\u5426\u5728\u767D\u76D2\u7EA7\u522B\u8FDB\u884C\u6027\u80FD\u6D4B\u8BD5\uFF1B</li><li>\u662F\u5426\u8003\u8651\u524D\u7AEF\u6027\u80FD\u7684\u4F18\u5316\uFF1B</li><li>\u5FC5\u8981\u7684\u65F6\u5019\u662F\u5426\u91C7\u7528\u6570\u636E\u538B\u7F29\u4F20\u8F93\uFF1B</li><li>\u5BF9\u4E8E\u65E2\u8981\u538B\u7F29\u53C8\u8981\u52A0\u5BC6\u7684\u573A\u666F\uFF0C\u662F\u5426\u91C7\u7528\u5148\u538B\u7F29\u540E\u52A0\u5BC6\u7684\u987A\u5E8F\u3002</li></ul><p><strong>\u7B2C\u56DB\uFF0C\u6570\u636E\u5E93\u76F8\u5173\u7684\u70B9\uFF1A</strong></p><ul><li>\u6570\u636E\u5E93\u8868\u8BBE\u8BA1\u662F\u5426\u9AD8\u6548\uFF1B</li><li>\u662F\u5426\u5F15\u5165\u5FC5\u8981\u7684\u7D22\u5F15\uFF1B</li><li>SQL \u8BED\u53E5\u7684\u6267\u884C\u8BA1\u5212\u662F\u5426\u5408\u7406\uFF1B</li><li>SQL \u8BED\u53E5\u9664\u4E86\u529F\u80FD\u662F\u5426\u8981\u8003\u8651\u6027\u80FD\u8981\u6C42\uFF1B</li><li>\u6570\u636E\u5E93\u662F\u5426\u9700\u8981\u5F15\u5165\u8BFB\u5199\u5206\u79BB\u673A\u5236\uFF1B</li><li>\u7CFB\u7EDF\u51B7\u542F\u52A8\u540E\uFF0C\u7F13\u5B58\u5927\u91CF\u4E0D\u547D\u4E2D\u7684\u65F6\u5019\uFF0C\u6570\u636E\u5E93\u627F\u8F7D\u7684\u538B\u529B\u662F\u5426\u8D85\u8D1F\u8377\u3002</li></ul><p><strong>\u7B2C\u4E94\uFF0C\u8F6F\u4EF6\u6027\u80FD\u7684\u53EF\u6D4B\u8BD5\u6027\u5305\u542B\u7684\u70B9\uFF1A</strong></p><ul><li>\u662F\u5426\u4E3A\u6027\u80FD\u5206\u6790\uFF08Profiler\uFF09\u63D0\u4F9B\u5FC5\u8981\u7684\u63A5\u53E3\u652F\u6301\uFF1B</li><li>\u662F\u5426\u652F\u6301\u9AD8\u5E76\u53D1\u573A\u666F\u4E0B\u7684\u6027\u80FD\u6253\u70B9\uFF1B</li><li>\u662F\u5426\u652F\u6301\u5168\u94FE\u8DEF\u7684\u6027\u80FD\u5206\u6790\u3002</li></ul><p>\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u8F6F\u4EF6\u5F00\u53D1\u4EBA\u5458\u4E00\u822C\u4E0D\u4F1A\u5173\u6CE8\u7CFB\u7EDF\u90E8\u7F72\u7EA7\u522B\u7684\u6027\u80FD\uFF0C\u6BD4\u5982\u8F6F\u4EF6\u8FD0\u884C\u76EE\u6807\u64CD\u4F5C\u7CFB\u7EDF\u7684\u8C03\u4F18\u3001\u5E94\u7528\u670D\u52A1\u5668\u7684\u53C2\u6570\u8C03\u4F18\u3001\u6570\u636E\u5E93\u7684\u53C2\u6570\u8C03\u4F18\u3001\u7F51\u7EDC\u73AF\u5883\u7684\u8C03\u4F18\u7B49\u3002</p><p>\u7CFB\u7EDF\u90E8\u7F72\u7EA7\u522B\u7684\u6027\u80FD\u6D4B\u8BD5\uFF0C\u76EE\u524D\u4E00\u822C\u662F\u5728\u7CFB\u7EDF\u6027\u80FD\u6D4B\u8BD5\u9636\u6BB5\u6216\u8005\u7CFB\u7EDF\u5BB9\u91CF\u89C4\u5212\u9636\u6BB5\uFF0C\u7531\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u3001\u7CFB\u7EDF\u67B6\u6784\u5E08\uFF0C\u4EE5\u53CA\u6570\u636E\u5E93\u7BA1\u7406\u5458\uFF08DBA\uFF09\u534F\u4F5C\u5B8C\u6210\u3002</p><p><strong>\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u773C\u4E2D\u7684\u8F6F\u4EF6\u6027\u80FD</strong></p><p>\u4ECE\u6027\u80FD\u5DE5\u7A0B\u7684\u89D2\u5EA6\u770B\uFF0C\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u5173\u6CE8\u7684\u662F\u7B97\u6CD5\u8BBE\u8BA1\u3001\u67B6\u6784\u8BBE\u8BA1\u3001\u6027\u80FD\u6700\u4F73\u5B9E\u8DF5\u3001\u6570\u636E\u5E93\u76F8\u5173\u3001\u8F6F\u4EF6\u6027\u80FD\u7684\u53EF\u6D4B\u8BD5\u6027\u8FD9\u4E94\u5927\u65B9\u9762\u3002</p><p>\u5728\u7CFB\u7EDF\u67B6\u6784\u5E08\u3001DBA\uFF0C\u4EE5\u53CA\u5F00\u53D1\u4EBA\u5458\u7684\u534F\u52A9\u4E0B\uFF0C\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u65E2\u8981\u80FD\u591F\u51C6\u786E\u628A\u63E1\u8F6F\u4EF6\u7684\u6027\u80FD\u9700\u6C42\uFF0C\u53C8\u8981\u80FD\u591F\u51C6\u786E\u5B9A\u4F4D\u5F15\u8D77\u201C\u4E0D\u597D\u201D\u6027\u80FD\u8868\u73B0\u7684\u5236\u7EA6\u56E0\u7D20\u548C\u6839\u6E90\uFF0C\u5E76\u63D0\u51FA\u76F8\u5E94\u7684\u89E3\u51B3\u65B9\u6848\u3002</p><p>\u4E00\u4E2A\u4F18\u79C0\u7684\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u4E00\u822C\u9700\u8981\u5177\u6709\u4EE5\u4E0B\u6280\u80FD\uFF1A</p><ul><li>\u6027\u80FD\u9700\u6C42\u7684\u603B\u7ED3\u548C\u62BD\u8C61\u80FD\u529B\uFF1B</li><li>\u6839\u636E\u6027\u80FD\u6D4B\u8BD5\u76EE\u6807\uFF0C\u7CBE\u51C6\u7684\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u8BBE\u8BA1\u548C\u8BA1\u7B97\u80FD\u529B\uFF1B</li><li>\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u548C\u6027\u80FD\u6D4B\u8BD5\u811A\u672C\u7684\u5F00\u53D1\u548C\u6267\u884C\u80FD\u529B\uFF1B</li><li>\u6D4B\u8BD5\u6027\u80FD\u62A5\u544A\u7684\u5206\u6790\u89E3\u8BFB\u80FD\u529B\uFF1B</li><li>\u6027\u80FD\u74F6\u9888\u7684\u5FEB\u901F\u6392\u67E5\u548C\u5B9A\u4F4D\u80FD\u529B\uFF1B</li><li>\u6027\u80FD\u6D4B\u8BD5\u6570\u636E\u7684\u8BBE\u8BA1\u548C\u5B9E\u73B0\u80FD\u529B\uFF1B</li><li>\u9762\u5BF9\u4E92\u8054\u7F51\u4EA7\u54C1\uFF0C\u5168\u94FE\u8DEF\u538B\u6D4B\u7684\u8BBE\u8BA1\u4E0E\u6267\u884C\u80FD\u529B\uFF0C\u80FD\u591F\u548C\u7CFB\u7EDF\u67B6\u6784\u5E08\u4E00\u8D77\u5904\u7406\u6D41\u91CF\u6807\u8BB0\u3001\u5F71\u5B50\u6570\u636E\u5E93\u7B49\u7684\u6280\u672F\u8BBE\u8BA1\u80FD\u529B\uFF1B</li><li>\u6DF1\u5165\u7406\u89E3\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u7684\u5185\u90E8\u5B9E\u73B0\u539F\u7406\uFF0C\u5F53\u6027\u80FD\u6D4B\u8BD5\u5DE5\u5177\u6709\u9650\u5236\u65F6\uFF0C\u53EF\u4EE5\u8FDB\u884C\u6269\u5C55\u4E8C\u6B21\u5F00\u53D1\uFF1B \u6781\u5176\u5BBD\u5E7F\u7684\u77E5\u8BC6\u9762\uFF0C\u65E2\u8981\u6709\u201C\u9762\u201D\u7684\u77E5\u8BC6\uFF0C\u6BD4\u5982\u7CFB\u7EDF\u67B6\u6784\u3001\u5B58\u50A8\u67B6\u6784\u3001\u7F51\u7EDC\u67B6\u6784\u7B49\u5168\u5C40\u7684\u77E5\u8BC6\uFF0C\u8FD8\u8981\u6709\u5927\u91CF\u201C\u70B9\u201D\u7684\u77E5\u8BC6\u79EF\u7D2F\uFF0C\u6BD4\u5982\u6570\u636E\u5E93 SQL \u8BED\u53E5\u7684\u6267\u884C\u8BA1\u5212\u8C03\u4F18\u3001JVM \u5783\u573E\u56DE\u6536\uFF08GC\uFF09\u673A\u5236\u3001\u591A\u7EBF\u7A0B\u5E38\u89C1\u95EE\u9898\u7B49\u7B49\u3002</li></ul><p>\u770B\u5230\u5982\u6B64\u591A\u7684\u6280\u80FD\u8981\u6C42\u4F60\u53EF\u80FD\u6709\u70B9\u5BB3\u6015\uFF0C\u7684\u786E\uFF0C\u6027\u80FD\u6D4B\u8BD5\u7684\u4E13\u4E1A\u6027\u6BD4\u8F83\u5F3A\uFF0C\u6211\u7ECF\u5E38\u628A\u4F18\u79C0\u7684\u6027\u80FD\u5DE5\u7A0B\u5E08\u6BD4\u4F5C\u662F\u4F18\u79C0\u7684\u533B\u751F\uFF0C\u4E5F\u662F\u8FD9\u4E2A\u539F\u56E0\u3002\u4F60\u9700\u8981\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u79EF\u7D2F\u5927\u91CF\u7684\u5B9E\u9645\u6848\u4F8B\uFF0C\u624D\u80FD\u6162\u6162\u57F9\u517B\u6240\u8C13\u7684\u201C\u6027\u80FD\u76F4\u89C9\u201D\uFF0C\u4ECE\u6211\u4E2A\u4EBA\u7684\u5B66\u4E60\u8DEF\u5F84\u6765\u8BB2\u4E5F\u662F\u5982\u6B64\u3002</p><p>\u5929\u4E0B\u65E0\u96BE\u4E8B\u53EA\u6015\u6709\u5FC3\u4EBA\uFF0C\u6240\u4EE5\u6293\u4F4F\u4E00\u5207\u53EF\u4EE5\u5145\u5B9E\u81EA\u5DF1\u7684\u673A\u4F1A\u5427\uFF0C\u6211\u4EEC\u7EC8\u5C06\u4F1A\u7834\u8327\u6210\u8776\u3002</p><p>\u8FD9\u5C31\u662F\u7EC8\u7AEF\u7528\u6237\u3001\u7CFB\u7EDF\u8FD0\u7EF4\u5DE5\u7A0B\u5E08\u3001\u8F6F\u4EF6\u5F00\u53D1\u5DE5\u7A0B\u5E08\uFF0C\u4EE5\u53CA\u6027\u80FD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u773C\u4E2D\u7684\u6027\u80FD\u6D4B\u8BD5\u4E86\uFF0C\u81F3\u6B64\u6211\u4EEC\u4E5F\u5C31\u975E\u5E38\u5BB9\u6613\u7406\u89E3\uFF0C\u4E0D\u540C\u7684\u7FA4\u4F53\u5BF9\u540C\u4E00\u4E2A\u7CFB\u7EDF\u7684\u6027\u80FD\u8981\u6C42\u4E3A\u4EC0\u4E48\u4F1A\u5982\u6B64\u4E0D\u540C\u3002</p><p>\u73B0\u5728\uFF0C<strong>\u6211\u518D\u6765\u548C\u4F60\u8BF4\u8BF4\u8861\u91CF\u8F6F\u4EF6\u6027\u80FD\u7684\u4E09\u4E2A\u6700\u5E38\u7528\u7684\u6307\u6807\uFF1A\u5E76\u53D1\u7528\u6237\u6570\u3001\u54CD\u5E94\u65F6\u95F4\uFF0C\u4EE5\u53CA\u7CFB\u7EDF\u541E\u5410\u91CF</strong>\u3002\u53EA\u8981\u4F60\u63A5\u89E6\u8FC7\u6027\u80FD\u6D4B\u8BD5\uFF0C\u6216\u8005\u4F60\u7684\u56E2\u961F\u5F00\u5C55\u8FC7\u6027\u80FD\u6D4B\u8BD5\uFF0C\u4F60\u90FD\u5E94\u8BE5\u542C\u8BF4\u8FD9\u4E09\u4E2A\u6307\u6807\u3002\u4F46\u5176\u5B9E\u5F88\u591A\u4EBA\u5BF9\u5B83\u4EEC\u7684\u7406\u89E3\u8FD8\u90FD\u505C\u7559\u5728\u8868\u9762\uFF0C\u5E76\u6CA1\u6709\u6DF1\u5165\u7EC6\u81F4\u5730\u8003\u8651\u8FC7\u5176\u672C\u8D28\u4E0E\u5185\u6DB5\uFF0C\u8FD9\u4E5F\u5BFC\u81F4\u4E86\u6027\u80FD\u6D4B\u8BD5\u5F88\u591A\u65F6\u5019\u5E76\u6CA1\u6709\u53D1\u6325\u5E94\u6709\u7684\u4F5C\u7528\u3002</p><p>\u56E0\u6B64\uFF0C\u63A5\u4E0B\u6765\u6211\u4F1A\u548C\u4F60\u6DF1\u5165\u5730\u804A\u804A\u8FD9\u4E09\u4E2A\u6307\u6807\u7684\u5185\u6DB5\u548C\u5916\u5EF6\uFF0C\u5E2E\u52A9\u4F60\u83B7\u5F97\u4E00\u4E2A\u5168\u65B0\u7684\u8BA4\u8BC6\u3002</p><p><strong>\u5E76\u53D1\u7528\u6237\u6570</strong></p><p><strong>\u5E76\u53D1\u7528\u6237\u6570\uFF0C\u662F\u6027\u80FD\u9700\u6C42\u4E0E\u6D4B\u8BD5\u6700\u5E38\u7528\uFF0C\u4E5F\u662F\u6700\u91CD\u8981\u7684\u6307\u6807\u4E4B\u4E00\u3002\u5B83\u5305\u542B\u4E86\u4E1A\u52A1\u5C42\u9762\u548C\u540E\u7AEF\u670D\u52A1\u5668\u5C42\u9762\u7684\u4E24\u5C42\u542B\u4E49</strong>\u3002</p><ul><li>\u4E1A\u52A1\u5C42\u9762\u7684\u5E76\u53D1\u7528\u6237\u6570\uFF0C\u6307\u7684\u662F\u5B9E\u9645\u4F7F\u7528\u7CFB\u7EDF\u7684\u7528\u6237\u603B\u6570\u3002\u4F46\u662F\uFF0C\u5355\u9760\u8FD9\u4E2A\u6307\u6807\u5E76\u4E0D\u80FD\u53CD\u6620\u7CFB\u7EDF\u5B9E\u9645\u627F\u8F7D\u7684\u538B\u529B\uFF0C\u6211\u4EEC\u8FD8\u8981\u7ED3\u5408\u7528\u6237\u884C\u4E3A\u6A21\u578B\u624D\u80FD\u5F97\u5230\u7CFB\u7EDF\u5B9E\u9645\u627F\u8F7D\u7684\u538B\u529B\u3002</li><li>\u540E\u7AEF\u670D\u52A1\u5668\u5C42\u9762\u7684\u5E76\u53D1\u7528\u6237\u6570\uFF0C\u6307\u7684\u662F\u201C\u540C\u65F6\u5411\u670D\u52A1\u5668\u53D1\u9001\u8BF7\u6C42\u7684\u6570\u91CF\u201D\uFF0C\u76F4\u63A5\u53CD\u6620\u4E86\u7CFB\u7EDF\u5B9E\u9645\u627F\u8F7D\u7684\u538B\u529B\u3002</li></ul><p>\u4E3A\u4E86\u8BA9\u4F60\u66F4\u597D\u5730\u7406\u89E3\u8FD9\u4E24\u5C42\u542B\u4E49\u4E4B\u95F4\u7684\u533A\u522B\uFF0C\u6211\u4EEC\u5148\u4E00\u8D77\u6765\u770B\u4E00\u4E2A\u5B9E\u4F8B\uFF1A\u4E00\u4E2A\u5DF2\u7ECF\u6295\u5165\u8FD0\u884C\u7684 ERP \u7CFB\u7EDF\uFF0C\u8BE5\u7CFB\u7EDF\u6240\u5728\u4F01\u4E1A\u5171\u6709 5000 \u540D\u5458\u5DE5\u5E76\u90FD\u62E5\u6709\u8D26\u53F7\uFF0C\u4E5F\u5C31\u662F\u8BF4\u8FD9\u4E2A\u7CFB\u7EDF\u6709 5000 \u4E2A\u6F5C\u5728\u7528\u6237\u3002</p><p>\u6839\u636E\u7CFB\u7EDF\u65E5\u5FD7\u5206\u6790\u5F97\u77E5\uFF0C\u8BE5\u7CFB\u7EDF\u6700\u5927\u5728\u7EBF\u7528\u6237\u6570\u662F 2500 \u4EBA\uFF0C\u90A3\u4E48\u4ECE\u5B8F\u89C2\u89D2\u5EA6\u6765\u770B\uFF0C2500 \u5C31\u662F\u8FD9\u4E2A\u7CFB\u7EDF\u7684\u6700\u5927\u5E76\u53D1\u7528\u6237\u6570\u3002\u4F46\u662F\uFF0C2500 \u8FD9\u4E2A\u6570\u636E\u4EC5\u4EC5\u662F\u8BF4\u5728\u6700\u9AD8\u5CF0\u65F6\u6BB5\u6709 2500 \u4E2A\u7528\u6237\u767B\u5F55\u4E86\u7CFB\u7EDF\uFF0C\u800C\u670D\u52A1\u5668\u6240\u627F\u53D7\u7684\u538B\u529B\u53D6\u51B3\u4E8E\u767B\u5F55\u7528\u6237\u7684\u884C\u4E3A\uFF0C\u6240\u4EE5\u5B83\u5E76\u4E0D\u80FD\u51C6\u786E\u8868\u73B0\u670D\u52A1\u5668\u6B64\u65F6\u6B64\u523B\u6B63\u5728\u627F\u53D7\u7684\u538B\u529B\u3002</p><p>\u5047\u8BBE\u5728\u67D0\u4E00\u65F6\u95F4\u70B9\u4E0A\uFF0C\u8FD9 2500 \u4E2A\u7528\u6237\u4E2D\uFF0C30%\u7528\u6237\u5904\u4E8E\u9875\u9762\u6D4F\u89C8\u72B6\u6001\uFF08\u5BF9\u670D\u52A1\u5668\u6CA1\u6709\u53D1\u8D77\u8BF7\u6C42\uFF09\uFF0C20%\u7528\u6237\u5728\u586B\u5199\u8BA2\u5355\uFF08\u4E5F\u6CA1\u6709\u5BF9\u670D\u52A1\u5668\u53D1\u8D77\u8BF7\u6C42\uFF09\uFF0C5%\u7528\u6237\u5728\u9012\u4EA4\u8BA2\u5355\uFF0C15%\u7528\u6237\u5728\u67E5\u8BE2\u8BA2\u5355\uFF0C\u800C\u53E6\u5916\u7684 30%\u7528\u6237\u6CA1\u6709\u8FDB\u884C\u4EFB\u4F55\u64CD\u4F5C\u3002\u90A3\u4E48\u6B64\u65F6\uFF0C\u8FD9 2500 \u4E2A\u201C\u5E76\u53D1\u7528\u6237\u201D\u4E2D\u771F\u6B63\u5BF9\u670D\u52A1\u5668\u4EA7\u751F\u538B\u529B\u7684\u53EA\u6709 500 \u4E2A\u7528\u6237\uFF08\uFF085%+15%\uFF09*2500=500\uFF09\u3002</p><p>\u5728\u8FD9\u4E2A\u4F8B\u5B50\u4E2D\uFF0C5000 \u662F\u6700\u5927\u7684\u201C\u7CFB\u7EDF\u6F5C\u5728\u7528\u6237\u6570\u201D\uFF0C2500 \u662F\u6700\u5927\u7684\u201C\u4E1A\u52A1\u5E76\u53D1\u7528\u6237\u6570\u201D\uFF0C500 \u5219\u662F\u67D0\u4E2A\u65F6\u95F4\u70B9\u4E0A\u7684\u201C\u5B9E\u9645\u5E76\u53D1\u7528\u6237\u6570\u201D\u3002\u800C\u6B64\u65F6\u8FD9 500 \u4E2A\u7528\u6237\u540C\u65F6\u6267\u884C\u4E1A\u52A1\u64CD\u4F5C\u6240\u5B9E\u9645\u89E6\u53D1\u7684\u670D\u52A1\u5668\u7AEF\u7684\u6240\u6709\u8C03\u7528\uFF0C\u53EB\u4F5C\u201C\u670D\u52A1\u5668\u5E76\u53D1\u8BF7\u6C42\u6570\u201D\u3002</p><p>\u4ECE\u8FD9\u4E2A\u4F8B\u5B50\u53EF\u4EE5\u770B\u51FA\uFF0C\u5728\u7CFB\u7EDF\u8FD0\u884C\u671F\u95F4\u7684\u67D0\u4E2A\u65F6\u95F4\u70B9\u4E0A\uFF0C\u6709\u4E00\u4E2A\u6307\u6807\u53EB\u4F5C\u201C\u540C\u65F6\u5411\u670D\u52A1\u5668\u53D1\u9001\u8BF7\u6C42\u7684\u6570\u91CF\u201D\uFF0C\u8FD9\u4E2A\u201C\u540C\u65F6\u5411\u670D\u52A1\u5668\u53D1\u9001\u8BF7\u6C42\u7684\u6570\u91CF\u201D\u5C31\u662F\u670D\u52A1\u5668\u5C42\u9762\u7684\u5E76\u53D1\u7528\u6237\u6570\uFF0C\u8FD9\u4E2A\u6307\u6807\u540C\u65F6\u53D6\u51B3\u4E8E\u4E1A\u52A1\u5E76\u53D1\u7528\u6237\u6570\u548C\u7528\u6237\u884C\u4E3A\u6A21\u5F0F\uFF0C\u800C\u4E14\u7528\u6237\u884C\u4E3A\u6A21\u5F0F\u5360\u7684\u6BD4\u91CD\u8F83\u5927\u3002</p><p>\u56E0\u6B64\uFF0C\u5206\u6790\u5F97\u5230\u51C6\u786E\u7684\u7528\u6237\u884C\u4E3A\u6A21\u5F0F\uFF0C\u662F\u6027\u80FD\u6D4B\u8BD5\u4E2D\u7684\u5173\u952E\u4E00\u73AF\u3002\u4F46\uFF0C\u83B7\u5F97\u7CBE\u51C6\u7684\u7528\u6237\u884C\u4E3A\u6A21\u5F0F\uFF0C\u662F\u9664\u4E86\u83B7\u53D6\u6027\u80FD\u9700\u6C42\u5916\uFF0C\u6700\u56F0\u96BE\u7684\u5DE5\u4F5C\u3002</p><p>\u76EE\u524D\uFF0C\u83B7\u53D6\u7528\u6237\u884C\u4E3A\u6A21\u5F0F\u7684\u65B9\u6CD5\uFF0C\u4E3B\u8981\u5206\u4E3A\u4E24\u79CD\uFF1A</p><ul><li>\u5BF9\u4E8E\u5DF2\u7ECF\u4E0A\u7EBF\u7684\u7CFB\u7EDF\u6765\u8BF4\uFF0C\u5F80\u5F80\u91C7\u7528\u7CFB\u7EDF\u65E5\u5FD7\u5206\u6790\u6CD5\u83B7\u53D6\u7528\u6237\u884C\u4E3A\u7EDF\u8BA1\u548C\u5CF0\u503C\u5E76\u53D1\u91CF\u7B49\u91CD\u8981\u4FE1\u606F\uFF1B</li><li>\u800C\u5BF9\u4E8E\u672A\u4E0A\u7EBF\u7684\u5168\u65B0\u7CFB\u7EDF\u6765\u8BF4\uFF0C\u901A\u5E38\u7684\u505A\u6CD5\u662F\u53C2\u8003\u884C\u4E1A\u4E2D\u7C7B\u4F3C\u7CFB\u7EDF\u7684\u7EDF\u8BA1\u4FE1\u606F\u6765\u5EFA\u6A21\uFF0C\u7136\u540E\u5206\u6790\u3002</li></ul><p><strong>\u54CD\u5E94\u65F6\u95F4</strong></p><p><strong>\u901A\u4FD7\u6765\u8BB2\uFF0C\u54CD\u5E94\u65F6\u95F4\u53CD\u6620\u4E86\u5B8C\u6210\u67D0\u4E2A\u64CD\u4F5C\u6240\u9700\u8981\u7684\u65F6\u95F4\uFF0C\u5176\u6807\u51C6\u5B9A\u4E49\u662F\u201C\u5E94\u7528\u7CFB\u7EDF\u4ECE\u8BF7\u6C42\u53D1\u51FA\u5F00\u59CB\uFF0C\u5230\u5BA2\u6237\u7AEF\u63A5\u6536\u5230\u6700\u540E\u4E00\u4E2A\u5B57\u8282\u6570\u636E\u6240\u6D88\u8017\u7684\u65F6\u95F4\u201D\uFF0C\u662F\u7528\u6237\u89C6\u89D2\u8F6F\u4EF6\u6027\u80FD\u7684\u4E3B\u8981\u4F53\u73B0</strong>\u3002</p><p>\u54CD\u5E94\u65F6\u95F4\uFF0C\u5206\u4E3A\u524D\u7AEF\u5C55\u73B0\u65F6\u95F4\u548C\u7CFB\u7EDF\u54CD\u5E94\u65F6\u95F4\u4E24\u90E8\u5206\u3002\u5176\u4E2D\uFF0C\u524D\u7AEF\u65F6\u95F4\uFF0C\u53C8\u79F0\u5448\u73B0\u65F6\u95F4\uFF0C\u53D6\u51B3\u4E8E\u5BA2\u6237\u7AEF\u6536\u5230\u670D\u52A1\u5668\u8FD4\u56DE\u7684\u6570\u636E\u540E\u6E32\u67D3\u9875\u9762\u6240\u6D88\u8017\u7684\u65F6\u95F4\uFF1B\u800C\u7CFB\u7EDF\u54CD\u5E94\u65F6\u95F4\uFF0C\u53C8\u53EF\u4EE5\u8FDB\u4E00\u6B65\u5212\u5206\u4E3A Web \u670D\u52A1\u5668\u65F6\u95F4\u3001\u5E94\u7528\u670D\u52A1\u5668\u65F6\u95F4\u3001\u6570\u636E\u5E93\u65F6\u95F4\uFF0C\u4EE5\u53CA\u5404\u670D\u52A1\u5668\u95F4\u901A\u4FE1\u7684\u7F51\u7EDC\u65F6\u95F4\u3002</p><p>\u9664\u975E\u662F\u9488\u5BF9\u524D\u7AEF\u7684\u6027\u80FD\u6D4B\u8BD5\u4E0E\u8C03\u4F18\uFF0C\u8F6F\u4EF6\u7684\u6027\u80FD\u6D4B\u8BD5\u4E00\u822C\u66F4\u5173\u6CE8\u670D\u52A1\u5668\u7AEF\u3002\u4F46\u662F\uFF0C\u670D\u52A1\u5668\u7AEF\u54CD\u5E94\u65F6\u95F4\u7684\u6982\u5FF5\u975E\u5E38\u6E05\u6670\u3001\u76F4\u63A5\uFF0C\u5C31\u662F\u6307\u4ECE\u53D1\u51FA\u8BF7\u6C42\u8D77\u5230\u5904\u7406\u5B8C\u6210\u7684\u65F6\u95F4\uFF0C\u6CA1\u6709\u4E8C\u4E49\u6027\uFF1B\u800C\u524D\u7AEF\u65F6\u95F4\u7684\u5B9A\u4E49\uFF0C\u5728\u6211\u770B\u6765\u5B58\u5728\u4E9B\u6B67\u4E49\u3002\u6240\u4EE5\uFF0C\u63A5\u4E0B\u6765\u6211\u4F1A\u548C\u4F60\u8BE6\u7EC6\u804A\u804A\u524D\u7AEF\u65F6\u95F4\u8FD9\u4E2A\u8BDD\u9898\u3002</p><p>\u867D\u7136\u524D\u7AEF\u65F6\u95F4\u4E00\u5B9A\u7A0B\u5EA6\u4E0A\u53D6\u51B3\u4E8E\u5BA2\u6237\u7AEF\u7684\u5904\u7406\u80FD\u529B\uFF0C\u4F46\u662F\u524D\u7AEF\u5F00\u53D1\u4EBA\u5458\u73B0\u5728\u8FD8\u4F1A\u4F7F\u7528\u4E00\u4E9B\u7F16\u7A0B\u6280\u5DE7\u5728\u6570\u636E\u5C1A\u672A\u5B8C\u5168\u63A5\u6536\u5B8C\u6210\u65F6\u5448\u73B0\u6570\u636E\uFF0C\u4EE5\u51CF\u5C11\u7528\u6237\u5B9E\u9645\u611F\u53D7\u5230\u7684\u4E3B\u89C2\u54CD\u5E94\u65F6\u95F4\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u6211\u4EEC\u73B0\u5728\u4F1A\u666E\u904D\u91C7\u7528\u63D0\u524D\u6E32\u67D3\u6280\u672F\uFF0C\u4F7F\u5F97\u7528\u6237\u5B9E\u9645\u611F\u53D7\u5230\u7684\u54CD\u5E94\u65F6\u95F4\u901A\u5E38\u8981\u5C0F\u4E8E\u6807\u51C6\u5B9A\u4E49\u7684\u54CD\u5E94\u65F6\u95F4\u3002</p><p>\u9274\u4E8E\u6B64\uFF0C<strong>\u6211\u8BA4\u4E3A\u54CD\u5E94\u65F6\u95F4\u7684\u6807\u51C6\u5B9A\u4E49\u5C31\u4E0D\u5C3D\u5408\u7406\u4E86\uFF0C\u5C24\u5176\u662F\u5BF9\u4E8E\u201C\u63A5\u6536\u5230\u6700\u540E\u4E00\u4E2A\u5B57\u8282\u201D</strong>\u3002</p><p>\u6211\u6765\u4E3E\u4E2A\u5B9E\u9645\u6848\u4F8B\u5427\u3002\u52A0\u8F7D\u4E00\u4E2A\u7F51\u9875\u65F6\uFF0C\u5982\u679C 10 \u79D2\u540E\u8FD8\u662F\u767D\u5C4F\uFF0C\u90A3\u4F60\u4E00\u5B9A\u4F1A\u611F\u89C9\u5F88\u6162\u3001\u6027\u80FD\u65E0\u6CD5\u63A5\u53D7\u3002\u4F46\u662F\uFF0C\u56DE\u60F3\u4E00\u4E0B\u4F60\u66FE\u7ECF\u4E0A\u65B0\u6D6A\u7F51\u7684\u7ECF\u5386\uFF0C\u5F53\u52A0\u8F7D\u65B0\u6D6A\u9996\u9875\u65F6\uFF0C\u4F60\u5E94\u8BE5\u4E0D\u4F1A\u611F\u89C9\u901F\u5EA6\u5F88\u6162\u5427\u3002\u5176\u5B9E\uFF0C\u5B9E\u9645\u60C5\u51B5\u662F\uFF0C\u65B0\u6D6A\u9996\u9875\u7684\u52A0\u8F7D\u65F6\u95F4\u8981\u8FDC\u5927\u4E8E 10 \u79D2\uFF0C\u53EA\u662F\u65B0\u6D6A\u91C7\u7528\u4E86\u6570\u636E\u5C1A\u672A\u5B8C\u5168\u63A5\u6536\u5B8C\u6210\u65F6\u8FDB\u884C\u5448\u73B0\u7684\u6280\u672F\uFF0C\u5927\u5927\u7F29\u77ED\u4E86\u7528\u6237\u4E3B\u89C2\u611F\u53D7\u5230\u7684\u65F6\u95F4\uFF0C\u63D0\u5347\u4E86\u7528\u6237\u4F53\u9A8C\u3002</p><p>\u6240\u4EE5\uFF0C<strong>\u4E25\u683C\u6765\u8BB2\uFF0C\u54CD\u5E94\u65F6\u95F4\u5E94\u8BE5\u5305\u542B\u4E24\u5C42\u542B\u4E49\uFF1A\u6280\u672F\u5C42\u9762\u7684\u6807\u51C6\u5B9A\u4E49\u548C\u57FA\u4E8E\u7528\u6237\u4E3B\u89C2\u611F\u53D7\u65F6\u95F4\u7684\u5B9A\u4E49\u3002\u800C\u5728\u6027\u80FD\u6D4B\u8BD5\u8FC7\u7A0B\u4E2D\uFF0C\u6211\u4EEC\u5E94\u8BE5\u4F7F\u7528\u54EA\u4E2A\u5C42\u9762\u7684\u542B\u4E49\u5C06\u53D6\u51B3\u4E8E\u6027\u80FD\u6D4B\u8BD5\u7684\u7C7B\u578B</strong>\u3002\u663E\u7136\uFF0C\u5BF9\u4E8E\u8F6F\u4EF6\u670D\u52A1\u5668\u7AEF\u7684\u6027\u80FD\u6D4B\u8BD5\u80AF\u5B9A\u8981\u91C7\u7528\u6807\u51C6\u5B9A\u4E49\uFF0C\u800C\u5BF9\u4E8E\u524D\u7AEF\u6027\u80FD\u8BC4\u4F30\uFF0C\u5219\u5E94\u8BE5\u91C7\u7528\u7528\u6237\u4E3B\u89C2\u611F\u53D7\u65F6\u95F4\u7684\u5B9A\u4E49\u3002</p><p>\u5F53\u7136\uFF0C\u6211\u4EEC\u5728\u524D\u7AEF\u6027\u80FD\u6D4B\u8BD5\u4E2D\uFF0C\u4F1A\u5229\u7528\u4E00\u4E9B\u4E8B\u4EF6\u7684\u89E6\u53D1\uFF08\u6BD4\u5982 DOM-Load\u3001Page-load \u7B49\uFF09\u6765\u5BA2\u89C2\u5730\u8861\u91CF\u201C\u4E3B\u89C2\u7684\u524D\u7AEF\u6027\u80FD\u201D\u3002\u8FD9\u90E8\u5206\u5185\u5BB9\u6211\u4F1A\u5728\u540E\u9762\u4ECB\u7ECD\u524D\u7AEF\u6027\u80FD\u6D4B\u8BD5\u65F6\uFF0C\u548C\u4F60\u8BE6\u7EC6\u8BA8\u8BBA\u3002</p><p><strong>\u7CFB\u7EDF\u541E\u5410\u91CF</strong></p><p>\u7CFB\u7EDF\u541E\u5410\u91CF\uFF0C\u662F\u6700\u80FD\u76F4\u63A5\u4F53\u73B0\u8F6F\u4EF6\u7CFB\u7EDF\u8D1F\u8F7D\u627F\u53D7\u80FD\u529B\u7684\u6307\u6807\u3002</p><p>\u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C<strong>\u6240\u6709\u5BF9\u541E\u5410\u91CF\u7684\u8BA8\u8BBA\u90FD\u5FC5\u987B\u4EE5\u201C\u5355\u4F4D\u65F6\u95F4\u201D\u4F5C\u4E3A\u57FA\u672C\u524D\u63D0</strong>\u3002\u5176\u5B9E\uFF0C\u6211\u8BA4\u4E3A\u628A\u201CThroughput\u201D\u7FFB\u8BD1\u6210\u541E\u5410\u7387\u66F4\u8D34\u5207\uFF0C\u56E0\u4E3A\u6211\u4EEC\u53EF\u4EE5\u8FD9\u6837\u7406\u89E3\uFF1A\u541E\u5410\u7387=\u541E\u5410\u91CF/\u5355\u4F4D\u65F6\u95F4\u3002\u4F46\u65E2\u7136\u56FD\u5185\u5F88\u591A\u8D44\u6599\u5DF2\u7ECF\u7FFB\u8BD1\u4E3A\u4E86\u201C\u541E\u5410\u91CF\u201D\uFF0C\u6240\u4EE5\u901A\u5E38\u60C5\u51B5\u4E0B\u6211\u4EEC\u4E0D\u4F1A\u523B\u610F\u53BB\u533A\u5206\u541E\u5410\u91CF\u548C\u541E\u5410\u7387\uFF0C\u7EDF\u79F0\u4E3A\u541E\u5410\u91CF\u3002</p><p>\u5BF9\u6027\u80FD\u6D4B\u8BD5\u800C\u8A00\uFF0C\u901A\u5E38\u7528\u201CRequests/Second\u201D\u201CPages/Second\u201D\u201CBytes/Second\u201D\u6765\u8861\u91CF\u541E\u5410\u91CF\u3002\u5F53\u7136\uFF0C\u4ECE\u4E1A\u52A1\u7684\u89D2\u5EA6\u6765\u8BB2\uFF0C\u541E\u5410\u91CF\u4E5F\u53EF\u4EE5\u7528\u5355\u4F4D\u65F6\u95F4\u7684\u4E1A\u52A1\u5904\u7406\u6570\u91CF\u6765\u8861\u91CF\u3002</p><p>\u4EE5\u4E0D\u540C\u65B9\u5F0F\u8868\u8FBE\u7684\u541E\u5410\u91CF\u53EF\u4EE5\u8BF4\u660E\u4E0D\u540C\u5C42\u6B21\u7684\u95EE\u9898\u3002\u6BD4\u5982\uFF1A</p><ul><li>\u201CBytes/Second\u201D\u548C\u201CPages/Second\u201D\u8868\u793A\u7684\u541E\u5410\u91CF\uFF0C\u4E3B\u8981\u53D7\u7F51\u7EDC\u8BBE\u7F6E\u3001\u670D\u52A1\u5668\u67B6\u6784\u3001\u5E94\u7528\u670D\u52A1\u5668\u5236\u7EA6\uFF1B</li><li>\u201CRequests/Second\u201D\u8868\u793A\u7684\u541E\u5410\u91CF\uFF0C\u4E3B\u8981\u53D7\u5E94\u7528\u670D\u52A1\u5668\u548C\u5E94\u7528\u672C\u8EAB\u5B9E\u73B0\u7684\u5236\u7EA6\u3002 \u8FD9\u91CC\u9700\u8981\u7279\u522B\u6CE8\u610F\u7684\u662F\uFF1A\u867D\u8BF4\u541E\u5410\u91CF\u53EF\u4EE5\u53CD\u6620\u670D\u52A1\u5668\u627F\u53D7\u8D1F\u8F7D\u7684\u60C5\u51B5\uFF0C\u4F46\u5728\u4E0D\u540C\u5E76\u53D1\u7528\u6237\u6570\u7684\u573A\u666F\u4E0B\uFF0C\u5373\u4F7F\u7CFB\u7EDF\u5177\u6709\u76F8\u8FD1\u7684\u541E\u5410\u91CF\uFF0C\u4F46\u662F\u5F97\u5230\u7684\u7CFB\u7EDF\u6027\u80FD\u74F6\u9888\u4E5F\u4F1A\u76F8\u5DEE\u751A\u8FDC\u3002</li></ul><p>\u6BD4\u5982\uFF0C\u67D0\u4E2A\u6D4B\u8BD5\u573A\u666F\u4E2D\u91C7\u7528 100 \u4E2A\u5E76\u53D1\u7528\u6237\uFF0C\u6BCF\u4E2A\u7528\u6237\u6BCF\u9694 1 \u79D2\u53D1\u51FA\u4E00\u4E2A Request\uFF0C\u53E6\u5916\u4E00\u4E2A\u6D4B\u8BD5\u573A\u666F\u91C7\u7528 1000 \u4E2A\u5E76\u53D1\u7528\u6237\uFF0C\u6BCF\u4E2A\u7528\u6237\u6BCF\u9694 10 \u79D2\u53D1\u51FA\u4E00\u4E2A Request\u3002\u663E\u7136\u8FD9\u4E24\u4E2A\u573A\u666F\u5177\u6709\u76F8\u540C\u7684\u541E\u5410\u91CF, \u90FD\u662F 100 Requests/second\uFF0C\u4F46\u662F\u4E24\u79CD\u573A\u666F\u4E0B\u7684\u7CFB\u7EDF\u6027\u80FD\u62D0\u70B9\u80AF\u5B9A\u4E0D\u540C\u3002\u56E0\u4E3A\uFF0C\u4E24\u4E2A\u573A\u666F\u6240\u5360\u7528\u7684\u8D44\u6E90\u662F\u4E0D\u540C\u7684\u3002</p><p>\u8FD9\u5C31\u8981\u6C42\u6027\u80FD\u6D4B\u8BD5\u573A\u666F\u7684\u6307\u6807\uFF0C\u5FC5\u7136\u4E0D\u662F\u5355\u4E2A\uFF0C\u9700\u8981\u6839\u636E\u5B9E\u9645\u60C5\u51B5\u7EC4\u5408\u5E76\u53D1\u7528\u6237\u6570\u3001\u54CD\u5E94\u65F6\u95F4\u8FD9\u4E24\u4E2A\u6307\u6807\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4F5C\u4E3A\u6027\u80FD\u6D4B\u8BD5\u7CFB\u5217\u7684\u7B2C\u4E00\u7BC7\u6587\u7AE0\uFF0C\u6211\u548C\u4F60\u4E00\u8D77\u68B3\u7406\u4E86\u8F6F\u4EF6\u6027\u80FD\u3001\u8F6F\u4EF6\u6027\u80FD\u6D4B\u8BD5\u76F8\u5173\u7684\u77E5\u8BC6\u70B9\uFF0C\u65E8\u5728\u4F60\u5BF9\u52A0\u6DF1\u8F6F\u4EF6\u6027\u80FD\u6307\u6807\u7684\u7406\u89E3\uFF0C\u4E3A\u540E\u7EED\u7684\u6027\u80FD\u6D4B\u8BD5\u5B9E\u6218\u6253\u597D\u57FA\u7840\u3002</p><p>\u9996\u5148\uFF0C\u6211\u4ECE\u7EC8\u7AEF\u7528\u6237\u3001\u7CFB\u7EDF\u8FD0\u7EF4\u4EBA\u5458\u3001\u8F6F\u4EF6\u8BBE\u8BA1\u5F00\u53D1\u4EBA\u5458\u548C\u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\uFF0C\u8FD9\u56DB\u4E2A\u7EF4\u5EA6\u4ECB\u7ECD\u4E86\u8F6F\u4EF6\u7CFB\u7EDF\u7684\u6027\u80FD\u5230\u5E95\u6307\u7684\u662F\u4EC0\u4E48\uFF1A</p><p>\u7EC8\u7AEF\u7528\u6237\u5E0C\u671B\u81EA\u5DF1\u7684\u4E1A\u52A1\u64CD\u4F5C\u8D8A\u5FEB\u8D8A\u597D\uFF1B \u7CFB\u7EDF\u8FD0\u7EF4\u4EBA\u5458\u8FFD\u6C42\u7CFB\u7EDF\u6574\u4F53\u7684\u5BB9\u91CF\u548C\u7A33\u5B9A\uFF1B \u5F00\u53D1\u4EBA\u5458\u4EE5\u201C\u6027\u80FD\u5DE5\u7A0B\u201D\u7684\u89C6\u89D2\u5173\u6CE8\u5B9E\u73B0\u8FC7\u7A0B\u7684\u6027\u80FD\uFF1B \u6027\u80FD\u6D4B\u8BD5\u4EBA\u5458\u9700\u8981\u5168\u76D8\u8003\u91CF\u3001\u5404\u4E2A\u51FB\u7834\u3002 \u7136\u540E\uFF0C\u6211\u4ECB\u7ECD\u4E86\u8F6F\u4EF6\u6027\u80FD\u7684\u4E09\u4E2A\u6700\u5E38\u7528\u7684\u6307\u6807\uFF1A\u5E76\u53D1\u7528\u6237\u6570\uFF0C\u54CD\u5E94\u65F6\u95F4\uFF0C\u7CFB\u7EDF\u541E\u5410\u91CF\uFF1A</p><p>\u5E76\u53D1\u7528\u6237\u6570\u5305\u542B\u4E0D\u540C\u5C42\u9762\u7684\u542B\u4E49\uFF0C\u65E2\u53EF\u4EE5\u6307\u5B9E\u9645\u7684\u5E76\u53D1\u7528\u6237\u6570\uFF0C\u4E5F\u53EF\u4EE5\u6307\u670D\u52A1\u5668\u7AEF\u7684\u5E76\u53D1\u6570\u91CF\uFF1B \u54CD\u5E94\u65F6\u95F4\u4E5F\u5305\u542B\u4E24\u5C42\u542B\u4E49\uFF0C\u6280\u672F\u5C42\u9762\u7684\u6807\u51C6\u5B9A\u4E49\u548C\u57FA\u4E8E\u7528\u6237\u4E3B\u89C2\u611F\u53D7\u65F6\u95F4\u7684\u5B9A\u4E49\uFF1B \u7CFB\u7EDF\u541E\u5410\u91CF\u662F\u6700\u80FD\u76F4\u63A5\u4F53\u73B0\u8F6F\u4EF6\u7CFB\u7EDF\u627F\u53D7\u8D1F\u8F7D\u80FD\u529B\u7684\u6307\u6807\uFF0C\u4F46\u4E5F\u5FC5\u987B\u548C\u5176\u4ED6\u6307\u6807\u4E00\u8D77\u4F7F\u7528\u624D\u80FD\u66F4\u597D\u5730\u8BF4\u660E\u95EE\u9898\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u7CFB\u7EDF\u541E\u5410\u91CF\u7684\u8868\u73B0\u5F62\u5F0F\u6709\u5F88\u591A\uFF0C\u6BD4\u5982\u201CRequests/Second\u201D\u201CPages/Second\u201D\u201CBytes/Second\u201D\u7B49\uFF0C\u4F60\u5728\u6027\u80FD\u6D4B\u8BD5\u9879\u76EE\u4E2D\uFF0C\u9009\u62E9\u5177\u4F53\u7684\u7CFB\u7EDF\u541E\u5410\u91CF\u6307\u6807\u65F6\uFF0C\u4F1A\u8003\u8651\u54EA\u4E9B\u56E0\u7D20\u5462\uFF1F</p>',85);function t(n,r){return s}var e=p(i,[["render",t],["__file","28.html.vue"]]);export{e as default};
